const data = $input.first().json || {};
const context = data.context || {};
const customer = context.customer || {};
const storefrontHandoff = context.storefront_handoff;
const candidateProducts = Array.isArray(context.candidate_products) ? context.candidate_products : [];
const interestedProductKey = String(customer.interested_product || '').trim();
const message = String(data.user_message || '').trim();
const normalized = message
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const unique = (values) => [...new Set(values.filter(Boolean))];
const brandRules = [
  ['apple', /(?:^|\s)(?:iphone|apple|ipad|macbook)(?=\s|\d|$)/i],
  ['samsung', /(?:^|\s)(?:samsung|samsumg|samgung|sansung|galaxy)(?=\s|\d|$)/i],
  ['motorola', /(?:^|\s)(?:motorola|moto)(?=\s|\d|$)/i],
  ['xiaomi', /(?:^|\s)(?:xiaomi|xaomi|xiami|xioami)(?=\s|\d|$)/i],
  ['redmi', /(?:^|\s)(?:redmi|redmy|rexmi|redim|remdi|poco)(?=\s|\d|$)/i],
  ['google', /(?:^|\s)(?:google|pixel)(?=\s|\d|$)/i],
  ['jbl', /(?:^|\s)(?:jbl)(?=\s|\d|$)/i],
];
const extractBrands = (text) => unique(brandRules.filter(([, pattern]) => pattern.test(text)).map(([brandKey]) => brandKey));
const extractTier = (text) => {
  if (/(^| )(pro max|promax)( |$)/.test(text)) return 'pro_max';
  if (/(^| )(ultra)( |$)/.test(text)) return 'ultra';
  if (/(^| )(pro)( |$)/.test(text)) return 'pro';
  if (/(^| )(plus)( |$)/.test(text)) return 'plus';
  return null;
};
const normalizeStorageValue = (rawValue) => {
  const value = Number(rawValue);
  if (!Number.isFinite(value)) return null;
  if (value >= 60 && value <= 70) return 64;
  if (value >= 118 && value <= 138) return 128;
  if (value >= 240 && value <= 270) return 256;
  if (value >= 480 && value <= 540) return 512;
  if (value >= 950 && value <= 1100) return 1024;
  return null;
};
const extractStorageValue = (text) => {
  const exactMatch = text.match(/\b(64|128|256|512|1024)\b(?:\s*gb)?\b/);
  if (exactMatch) return Number(exactMatch[1]);
  const approximateMatch =
    text.match(/\b(\d{2,4})\b(?=(?:\s*gb)?\s*(?:de\s+)?(?:memo\w*|almacen\w*|giga\w*|gb)\b)/i) ||
    text.match(/(?:memo\w*|almacen\w*|giga\w*|gb)\s*(?:de\s*)?\b(\d{2,4})\b/i);
  return approximateMatch ? normalizeStorageValue(Number(approximateMatch[1])) : null;
};
const extractRamValue = (text) => {
  const ramMatch =
    text.match(/\b(4|6|8|12|16)\b(?=(?:\s*gb)?\s*(?:de\s+)?ram\b)/i) ||
    text.match(/\bram\s*(?:de\s*)?\b(4|6|8|12|16)\b(?:\s*gb)?/i) ||
    text.match(/\b(4|6|8|12|16)\s*gb\s*ram\b/i);
  return ramMatch ? Number(ramMatch[1]) : null;
};

const requestedBrandKeys = extractBrands(normalized);
const tierKey = extractTier(normalized);
const storageValue = extractStorageValue(normalized);
const ramValue = extractRamValue(normalized);
const explicitFamilyMatch = normalized.match(/(?:iphone|galaxy|redmi|rexmi|redmy|redim|remdi|note|poco|moto|motorola|pixel|xiaomi|xaomi|xiami|xioami)\s*([0-9]{1,3})/i);
const modelVariantMatch = normalized.match(/\b(?:a\d{1,3}|s\d{1,3}|g\d{1,3}|x\d{1,3}|z\s?flip\s?\d|z\s?fold\s?\d|edge\s?\d{1,3}|note\s?\d{1,3}|reno\s?\d{1,3}|find\s?x\d{1,2})\b/i);
const asksPriceDirectly = /(precio|cuanto sale|cu[aá]nto sale|valor|costo|cotizacion|cotizaci[oó]n)/.test(normalized);
const asksCatalogLink = /(catalogo|cat[aá]logo|pagina|p[aá]gina|sitio|web|pasame el link|mandame el link|pasame la pagina|pasame la web|ver modelos|ver equipos|verlo aca|verlo ac[aá]|mostrame el link)/.test(normalized);
const asksComparison = /(cual de los dos|cu[aá]l de los dos|compar|versus|\bvs\b|mejor)/.test(normalized);
const asksImageRequest = /(foto|fotos|imagen|imagenes|como se ve|como es|mostrame|mandame foto|mandame imagen)/.test(normalized);
const wantsStoreInfo =
  /(ubicacion|direccion|sucursal|medios de pago|medio de pago|envio|envios|warranty|garantia|como llego|donde estan|donde quedan|retiro|mapa|horario|horarios|abren|cierran|feriado|feriados|plan canje|parte de pago|permuta|toma de usado|mayorista)/.test(normalized);
const asksProductFollowUp = /(cuotas|cuota|tarjeta|transferencia|efectivo|link de pago|pagar|pagarlo|entrega|envio|retiro|garantia|stock|disponible|color|colores|memoria|almacenamiento|ram|usd|dolar|promo|precio|foto|fotos|imagen|imagenes|como se ve|como es)/.test(normalized);
const usesRelativeReference = /(\b(ese|esa|este|esta|mismo|misma|anterior|quiero ese|quiero esa|dame ese|dame esa)\b|^y\b)/.test(normalized);
const customerBrandHints = Array.isArray(customer.brands_mentioned)
  ? customer.brands_mentioned.map((value) => String(value || '').trim().toLowerCase()).filter(Boolean)
  : [];
const candidateBrandHints = unique(
  candidateProducts.slice(0, 6).map((product) => String(product.brand_key || '').trim().toLowerCase()).filter(Boolean)
);
const threadBrandKeys = requestedBrandKeys.length === 0 ? unique([...customerBrandHints, ...candidateBrandHints]).slice(0, 2) : [];
const effectiveBrandKeys = requestedBrandKeys.length > 0 ? requestedBrandKeys : threadBrandKeys;
const hasConversationProductContext = Boolean(interestedProductKey || candidateProducts[0]?.product_key);
const hasSpecificProductIntent = Boolean(
  explicitFamilyMatch ||
    storageValue !== null ||
    ramValue !== null ||
    tierKey !== null ||
    modelVariantMatch ||
    asksPriceDirectly ||
    asksImageRequest ||
    asksComparison
);

let route_key = 'generic_sales';
let retrieval_scope = 'catalog_broad';
let search_mode = 'brand_gate';
let should_offer_store_url = false;
let should_offer_used_iphones = false;
let confidence = 0.72;
let rationale = 'Sin marca explícita: primero pedir aclaración.';
let use_info_responder = false;

if (storefrontHandoff && storefrontHandoff.ok === true) {
  route_key = 'storefront_order';
  retrieval_scope = 'storefront_handoff';
  search_mode = 'storefront_handoff';
  should_offer_store_url = false;
  confidence = 0.99;
  rationale = 'Se detectó un handoff válido de compra web.';
  use_info_responder = true;
} else if (wantsStoreInfo && requestedBrandKeys.length === 0 && !hasSpecificProductIntent) {
  route_key = 'store_info';
  retrieval_scope = 'store_info';
  search_mode = 'info';
  should_offer_store_url = asksCatalogLink;
  confidence = 0.94;
  rationale = 'Consulta de información general de la tienda.';
  use_info_responder = true;
} else if (
  hasConversationProductContext &&
  (usesRelativeReference || asksProductFollowUp) &&
  requestedBrandKeys.length === 0 &&
  !hasSpecificProductIntent
) {
  route_key = 'exact_product_quote';
  retrieval_scope = 'catalog_narrow';
  search_mode = interestedProductKey ? 'thread_context' : 'candidate_context';
  should_offer_store_url = false;
  confidence = interestedProductKey ? 0.93 : 0.86;
  rationale = 'Seguimiento del producto ya conversado.';
} else if (effectiveBrandKeys.length > 0 && hasSpecificProductIntent) {
  route_key = 'exact_product_quote';
  retrieval_scope = 'catalog_narrow';
  search_mode = requestedBrandKeys.length > 0 ? 'brand_exact' : 'thread_context';
  should_offer_store_url = false;
  confidence = candidateProducts.length > 0 ? 0.9 : 0.78;
  rationale = 'Consulta puntual dentro de una o más marcas concretas.';
} else if (effectiveBrandKeys.length > 0) {
  route_key = 'brand_catalog';
  retrieval_scope = 'catalog_broad';
  search_mode = effectiveBrandKeys.length > 1 ? 'multi_brand_catalog' : 'brand_catalog';
  should_offer_store_url = asksCatalogLink;
  confidence = effectiveBrandKeys.length > 1 ? 0.9 : 0.84;
  rationale = effectiveBrandKeys.length > 1 ? 'Consulta amplia de catálogo para dos marcas.' : 'Consulta amplia de catálogo por marca.';
} else {
  route_key = 'generic_sales';
  retrieval_scope = 'catalog_broad';
  search_mode = 'brand_gate';
  should_offer_store_url = asksCatalogLink;
  confidence = 0.7;
  rationale = 'Falta marca explícita: el bot debe pedir qué marca quiere ver.';
}

return [{
  json: {
    ...data,
    use_info_responder,
    router_output: {
      route_key,
      confidence,
      retrieval_scope,
      search_mode,
      should_offer_store_url,
      should_offer_used_iphones,
      requested_brand_keys: effectiveBrandKeys,
      matched_brand: effectiveBrandKeys[0] || null,
      selected_candidate_product_keys: candidateProducts.slice(0, 12).map((product) => product.product_key).filter(Boolean),
      rationale,
    },
  }
}];
